sql:
SELECT SUM(quantity) AS total_quantity_in_cart
FROM shopping_cart
WHERE user_id = 1;

external_knowledge:
- "Top-selling products" refers to products with the highest `total_sold` values;
- "Sales" refers to the total number of units sold (`total_sold`);
- "Ratings" refers to the average rating (`avg_rating`);
- "Discounted sales" refers to the number of units sold at a discounted price (`discounted_sold`);
- "Discounted revenue" refers to the total revenue generated from discounted sales (`discounted_revenue`).

- "blossomed in popularity" refers to the products with the highest number of reviews;
- "total inventory changes" refers to the sum of quantity changes in the inventory;
- "last date their inventory was adjusted" refers to the most recent date when the inventory for these products was changed.

- "products are like stars in the sky" refers to the products in the database;
- "users are the voyagers seeking the brightest ones" refers to the users in the database;
- "still shining (in stock)" means the products have a stock quantity greater than zero;
- "added to the voyagers' carts" refers to the products that are in the shopping cart;
- "number of times they've been collected (cart quantity)" refers to the quantity of the product in the cart;
- "their brilliance (price)" refers to the price of the product.

sql:
SELECT AVG(rating) AS average_rating
FROM product_reviews
WHERE product_id = 0;
